8	// TestExecuteBeadInstructions_ReportsGoUnderAttemptDir covers ddx-d532992f:
9	// both the claude-variant and agent-variant execute-bead prompts must steer
10	// investigation/report outputs into the per-attempt evidence directory
11	// (.ddx/executions/<run-id>/, surfaced as the {{.AttemptDir}} template slot)
12	// and explicitly forbid writing them to /tmp. A previous attempt (B15a)
13	// wrote its report to /tmp/feat-011-status.md, which the post-merge reviewer
14	// could not see and so flagged BLOCK.
15	func TestExecuteBeadInstructions_ReportsGoUnderAttemptDir(t *testing.T) {
16		cases := []struct {
17			name string
18			text string
19		}{
20			{"claude", executeBeadInstructionsClaudeText},
21			{"agent", executeBeadInstructionsAgentText},
22		}
23		for _, c := range cases {
24			t.Run(c.name, func(t *testing.T) {
25				if !strings.Contains(c.text, "{{.AttemptDir}}") {
26					t.Fatalf("%s prompt must reference {{.AttemptDir}} for evidence outputs", c.name)
27				}
28				if !strings.Contains(c.text, "/tmp") {
29					t.Fatalf("%s prompt must explicitly forbid writing reports to /tmp", c.name)
30				}
31				lower := strings.ToLower(c.text)
32				if !strings.Contains(lower, "report") {
33					t.Fatalf("%s prompt must mention report outputs convention", c.name)
34				}
35			})
36		}
37	}
38	
39	// TestExecuteBeadInstructions_AttemptDirSubstitutionForReports verifies that
40	// the {{.AttemptDir}} placeholder used by the new investigation/report
41	// guidance is rewritten by executeBeadInstructionsText's caller to the
42	// concrete .ddx/executions/<run-id>/ path, so agents see a real in-repo
43	// path, not the literal template token.
44	func TestExecuteBeadInstructions_AttemptDirSubstitutionForReports(t *testing.T) {
45		const fakeAttemptDir = ".ddx/executions/20260502T030443-test/"
46		for _, harness := range []string{"claude", "agent"} {
47			raw := executeBeadInstructionsText(harness)
48			if !strings.Contains(raw, "{{.AttemptDir}}") {
49				t.Fatalf("%s prompt missing {{.AttemptDir}} placeholder before substitution", harness)
50			}
51			substituted := strings.ReplaceAll(raw, "{{.AttemptDir}}", fakeAttemptDir)
52			if strings.Contains(substituted, "{{.AttemptDir}}") {
53				t.Fatalf("%s prompt still contains {{.AttemptDir}} after substitution", harness)
54			}
55			if !strings.Contains(substituted, fakeAttemptDir) {
56				t.Fatalf("%s prompt does not contain substituted attempt dir %q", harness, fakeAttemptDir)
57			}
58		}
59	}
