package agent

import (
	"crypto/sha256"
	"encoding/hex"
	"os"
	"testing"
)

func TestDumpPromptForCompare(t *testing.T) {
	for _, h := range []string{"claude", "agent"} {
		txt := executeBeadInstructionsText(h)
		sum := sha256.Sum256([]byte(txt))
		_ = os.WriteFile("/tmp/dump_"+h+".txt", []byte(txt), 0644)
		t.Logf("%s sha256=%s len=%d", h, hex.EncodeToString(sum[:]), len(txt))
	}
}
EOF
go test -run TestDumpPromptForCompare -v ./internal/agent/ 2>&1 | tail -20

